+    ["Sorta writes ", "your code."],
+    ["Sorta opens ", "your PRs."],
+    ["Sorta reviews ", "your diffs."],
+    ["Sorta keeps ", "sprints moving."],
+    ["Sorta does ", "your job."]
+  ];
+
+  var flipIndex = 0;
+  var container = document.getElementById("flipContainer");
+
+  function nextPhrase() {
+    var current = container.querySelector(".flip-text");
