+      current.classList.remove("flip-enter");
+      current.classList.add("flip-exit");
+      setTimeout(function() {
+        if (current.parentNode) current.parentNode.removeChild(current);
+      }, 600);
+    }
+
+    flipIndex = (flipIndex + 1) % phrases.length;
+    var el = document.createElement("div");
+    el.className = "flip-text flip-enter";
+    el.innerHTML = phrases[flipIndex][0] + '<span class="accent">' + phrases[flipIndex][1] + '</span>';
+    container.appendChild(el);
+  }
+
+  setInterval(nextPhrase, 3000);
+
+  // ---- Scroll reveal ----
+  var reveals = document.querySelectorAll("[data-reveal]");
+  var observer = new IntersectionObserver(function(entries) {
+    entries.forEach(function(entry) {
+      if (entry.isIntersecting) {
+        // Stagger siblings
+        var parent = entry.target.parentElement;
+        var siblings = parent.querySelectorAll("[data-reveal]");
+        var idx = Array.prototype.indexOf.call(siblings, entry.target);
+        setTimeout(function() {
+          entry.target.classList.add("visible");
+        }, idx * 100);
+        observer.unobserve(entry.target);
+      }
+    });
